/**
 * Proof tests for `wasm4pm-interview-site-pack`'s generated catalog
 * (`lib/capabilities.ts`). Cardinality and full-field assertions are
 * rendered from the same `capabilities` SPARQL binding that produced
 * `CAPABILITY_CATALOG` -- editing `ontology.ttl` changes both the catalog
 * and this proof on the next `ggen sync` together.
 *
 * Generated by `wasm4pm-interview-site-pack`.
 */
import { describe, expect, it } from "vitest";
import { CAPABILITY_CATALOG, capabilityInfo, isCapabilityId, executingCapabilityIds } from "../lib/capabilities";

const EXPECTED_TOTAL = 13;

describe("generated sandbox capability catalog", () => {
  it("has the SPARQL-derived total row count", () => {
    expect(CAPABILITY_CATALOG.length).toBe(EXPECTED_TOTAL);
  });

  it("has unique capability ids", () => {
    const ids = new Set(CAPABILITY_CATALOG.map((c) => c.id));
    expect(ids.size).toBe(EXPECTED_TOTAL);
  });

  it("has unique routes", () => {
    const routes = new Set(CAPABILITY_CATALOG.map((c) => c.route));
    expect(routes.size).toBe(EXPECTED_TOTAL);
  });

  it("full-field match for compile_python", () => {
    const info = capabilityInfo("compile_python");
    expect(info.label).toBe("CompilePython");
    expect(info.category).toBe("runtime");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/compile_python");
    expect(info.timeoutMs).toBe(5000);
    expect(info.authorityScope).toBe("sandbox.compile");
    expect(info.executesCode).toBe(true);
  });
  it("full-field match for compile_rust", () => {
    const info = capabilityInfo("compile_rust");
    expect(info.label).toBe("CompileRust");
    expect(info.category).toBe("runtime");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/compile_rust");
    expect(info.timeoutMs).toBe(60000);
    expect(info.authorityScope).toBe("sandbox.compile");
    expect(info.executesCode).toBe(true);
  });
  it("full-field match for create_file", () => {
    const info = capabilityInfo("create_file");
    expect(info.label).toBe("CreateFile");
    expect(info.category).toBe("editor");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/create_file");
    expect(info.timeoutMs).toBe(1000);
    expect(info.authorityScope).toBe("editor.write");
    expect(info.executesCode).toBe(false);
  });
  it("full-field match for create_session", () => {
    const info = capabilityInfo("create_session");
    expect(info.label).toBe("CreateSession");
    expect(info.category).toBe("session");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/create_session");
    expect(info.timeoutMs).toBe(2000);
    expect(info.authorityScope).toBe("session.create");
    expect(info.executesCode).toBe(false);
  });
  it("full-field match for execute_python", () => {
    const info = capabilityInfo("execute_python");
    expect(info.label).toBe("ExecutePython");
    expect(info.category).toBe("runtime");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/execute_python");
    expect(info.timeoutMs).toBe(10000);
    expect(info.authorityScope).toBe("sandbox.execute");
    expect(info.executesCode).toBe(true);
  });
  it("full-field match for execute_rust", () => {
    const info = capabilityInfo("execute_rust");
    expect(info.label).toBe("ExecuteRust");
    expect(info.category).toBe("runtime");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/execute_rust");
    expect(info.timeoutMs).toBe(10000);
    expect(info.authorityScope).toBe("sandbox.execute");
    expect(info.executesCode).toBe(true);
  });
  it("full-field match for extract_constraints", () => {
    const info = capabilityInfo("extract_constraints");
    expect(info.label).toBe("ExtractConstraints");
    expect(info.category).toBe("problem");
    expect(info.httpMethod).toBe("GET");
    expect(info.route).toBe("/api/sandbox/extract_constraints");
    expect(info.timeoutMs).toBe(2000);
    expect(info.authorityScope).toBe("problem.read");
    expect(info.executesCode).toBe(false);
  });
  it("full-field match for load_problem", () => {
    const info = capabilityInfo("load_problem");
    expect(info.label).toBe("LoadProblem");
    expect(info.category).toBe("problem");
    expect(info.httpMethod).toBe("GET");
    expect(info.route).toBe("/api/sandbox/load_problem");
    expect(info.timeoutMs).toBe(2000);
    expect(info.authorityScope).toBe("problem.read");
    expect(info.executesCode).toBe(false);
  });
  it("full-field match for modify_file", () => {
    const info = capabilityInfo("modify_file");
    expect(info.label).toBe("ModifyFile");
    expect(info.category).toBe("editor");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/modify_file");
    expect(info.timeoutMs).toBe(1000);
    expect(info.authorityScope).toBe("editor.write");
    expect(info.executesCode).toBe(false);
  });
  it("full-field match for open_file", () => {
    const info = capabilityInfo("open_file");
    expect(info.label).toBe("OpenFile");
    expect(info.category).toBe("editor");
    expect(info.httpMethod).toBe("GET");
    expect(info.route).toBe("/api/sandbox/open_file");
    expect(info.timeoutMs).toBe(1000);
    expect(info.authorityScope).toBe("editor.read");
    expect(info.executesCode).toBe(false);
  });
  it("full-field match for record_event", () => {
    const info = capabilityInfo("record_event");
    expect(info.label).toBe("RecordEvent");
    expect(info.category).toBe("session");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/record_event");
    expect(info.timeoutMs).toBe(2000);
    expect(info.authorityScope).toBe("session.record");
    expect(info.executesCode).toBe(false);
  });
  it("full-field match for run_cargo_test", () => {
    const info = capabilityInfo("run_cargo_test");
    expect(info.label).toBe("RunCargoTest");
    expect(info.category).toBe("verification");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/run_cargo_test");
    expect(info.timeoutMs).toBe(60000);
    expect(info.authorityScope).toBe("sandbox.execute");
    expect(info.executesCode).toBe(true);
  });
  it("full-field match for run_pytest", () => {
    const info = capabilityInfo("run_pytest");
    expect(info.label).toBe("RunPytest");
    expect(info.category).toBe("verification");
    expect(info.httpMethod).toBe("POST");
    expect(info.route).toBe("/api/sandbox/run_pytest");
    expect(info.timeoutMs).toBe(20000);
    expect(info.authorityScope).toBe("sandbox.execute");
    expect(info.executesCode).toBe(true);
  });

  it("rejects an unknown capability id", () => {
    expect(isCapabilityId("totally_unrelated_string")).toBe(false);
  });

  it("rejects the empty string", () => {
    expect(isCapabilityId("")).toBe(false);
  });

  it("capabilityInfo throws for an unknown id cast through as any", () => {
    expect(() => capabilityInfo("not_a_real_capability" as never)).toThrow();
  });

  // Real cross-check against wasm4pm-sandbox-pack's Rust catalog (packs/wasm4pm-sandbox-pack/ontology.ttl):
  // the six compile/execute/test capability ids must match exactly, since
  // they describe the same six capabilities from two runtime surfaces.
  it("shares the six compile/execute/test capability ids with the Rust sandbox catalog", () => {
    const sharedWithRustCatalog = [
      "compile_python",
      "execute_python",
      "run_pytest",
      "compile_rust",
      "execute_rust",
      "run_cargo_test",
    ];
    for (const id of sharedWithRustCatalog) {
      expect(isCapabilityId(id), `expected ${id} to be a real TS capability id`).toBe(true);
    }
  });

  it("executingCapabilityIds returns exactly the six code-executing capabilities", () => {
    const ids = executingCapabilityIds().slice().sort();
    expect(ids).toEqual(
      ["compile_python", "compile_rust", "execute_python", "execute_rust", "run_cargo_test", "run_pytest"].sort(),
    );
  });
});
